// MARK: - Password Reset Service

class PasswordResetService {
    
    static let shared = PasswordResetService()
    
    enum ResetError: Error, LocalizedError {
        case invalidToken
        case tokenExpired
        case networkError
        case serverError(String)
        
        var errorDescription: String? {
            switch self {
            case .invalidToken: return "The reset token is invalid."
            case .tokenExpired: return "The reset link has expired. Please request a new one."
            case .networkError: return "A network error occurred. Please check your connection and try again."
            case .serverError(let message): return message
            }
        }
    }
    
    private init() {}
    
    func resetPassword(token: String, newPassword: String, completion: @escaping (Result<Void, ResetError>) -> Void) {
        guard let url = URL(string: "https://api.myapp.com/v1/auth/reset-password") else {
            completion(.failure(.networkError))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body: [String: String] = [
            "token": token,
            "new_password": newPassword
        ]
        
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: body)
        } catch {
            completion(.failure(.networkError))
            return
        }
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if error != nil {
                completion(.failure(.networkError))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(.networkError))
                return
            }
            
            switch httpResponse.statusCode {
            case 200...299:
                completion(.success(()))
            case 400:
                completion(.failure(.invalidToken))
            case 410:
                completion(.failure(.tokenExpired))
            default:
                var message = "An unexpected error occurred."
                if let data = data,
                   let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                   let serverMessage = json["message"] as? String {
                    message = serverMessage
                }
                completion(.failure(.serverError(message)))
            }
        }.resume()
    }
}

